#include<bits/stdc++.h>
using namespace std;

const int N = 2e4 + 7;

int n, m, d[N], c, w[N], ans = 0, p[N];

struct Edge
{
	int v, w;
};

vector<Edge> e[N];

void dfs(int u, int fa) {
	for(auto [v, w] : e[u])
	{
		if(v == fa) continue;
		p[v] = w;
		dfs(v, u);
		d[u] = max(d[u], d[v] + w);
	}
	if(d[u] + p[u] >= m)
	{
		ans++;
		d[u] = 0;
	}
}

int main()
{
	int max_m = 0;
	cin >> n;
	for(int i = 1; i <= n; i++)
	{
		int k;
		cin >> k;
		for(int j = 1; j <= k; j++)
		{
			int v, w;
			cin >> v >> w;
			e[i].push_back({v, w});
			max_m = max(max_m, w);
		}
	}
	cin >> m;
	if(max_m >= m)
		cout << "No solution.", exit(0);
	dfs(1, 0);
	cout << ans;
}
